class Solution:
    def stoneGameII(self, piles):
        """
        :type piles: List[int]
        :rtype: int
        """
        n = len(piles)
        memo = {}
        suffix = [0] * (n + 1)

        # Compute suffix sums
        for i in range(n - 1, -1, -1):
            suffix[i] = suffix[i + 1] + piles[i]

        def dp(i, m):
            if i >= n:
                return 0
            if 2 * m >= n - i:
                return suffix[i]

            if (i, m) in memo:
                return memo[(i, m)]

            result = 0
            for x in range(1, 2 * m + 1):
                result = max(result, suffix[i] - dp(i + x, max(m, x)))

            memo[(i, m)] = result
            return result

        return dp(0, 1)
